// src/utils/sourceSerifFont.js
//
// Source Serif 4 (regular / italic / bold / bold-italic), Latin subset.
// Base64-encoded TTF files embedded for jsPDF so the generated PDF
// renders in a Georgia-adjacent serif that matches the on-screen preview.
//
// Source: Adobe Fonts / Google Fonts, licensed under SIL Open Font License 1.1.
// https://github.com/adobe-fonts/source-serif

export const SOURCE_SERIF_FONT_NAME = 'SourceSerif';

const NORMAL_BASE64 = '';

const ITALIC_BASE64 = '';

const BOLD_BASE64 = '';

const BOLD_ITALIC_BASE64 = '';

/**
 * Register Source Serif 4 with a jsPDF document.
 * After calling this, use `doc.setFont('SourceSerif', 'normal' | 'italic' | 'bold' | 'bolditalic')`.
 * Safe to call multiple times on the same doc.
 */
export function registerSourceSerif(doc) {
    if (doc._sourceSerifRegistered) return;
    doc.addFileToVFS('SourceSerif4-Regular.ttf', NORMAL_BASE64);
    doc.addFont('SourceSerif4-Regular.ttf', SOURCE_SERIF_FONT_NAME, 'normal');
    doc.addFileToVFS('SourceSerif4-Italic.ttf', ITALIC_BASE64);
    doc.addFont('SourceSerif4-Italic.ttf', SOURCE_SERIF_FONT_NAME, 'italic');
    doc.addFileToVFS('SourceSerif4-Bold.ttf', BOLD_BASE64);
    doc.addFont('SourceSerif4-Bold.ttf', SOURCE_SERIF_FONT_NAME, 'bold');
    doc.addFileToVFS('SourceSerif4-BoldItalic.ttf', BOLD_ITALIC_BASE64);
    doc.addFont('SourceSerif4-BoldItalic.ttf', SOURCE_SERIF_FONT_NAME, 'bolditalic');
    doc._sourceSerifRegistered = true;
}